import React, { useState, useEffect, useRef, useCallback } from 'react';
import { X, Plus, Maximize2, Minimize2, Settings } from 'lucide-react';

// Processador de códigos ANSI
function processAnsi(text) {
  if (!text) return '';
  
  // Remover sequencias ANSI de controle de cursor e outras
  let result = text
    // Cursor movement - ignorar mas manter funcionalidade
    .replace(/\x1b\[(\d+)A/g, '')  // cursor up
    .replace(/\x1b\[(\d+)B/g, '')  // cursor down
    .replace(/\x1b\[(\d+)C/g, '')  // cursor forward
    .replace(/\x1b\[(\d+)D/g, '')  // cursor back
    .replace(/\x1b\[(\d+);(\d+)H/g, '')  // cursor position
    .replace(/\x1b\[(\d+);(\d+)f/g, '')  // cursor position
    .replace(/\x1b\[H/g, '')  // cursor home
    .replace(/\x1b\[J/g, '')  // clear screen
    .replace(/\x1b\[2J/g, '')  // clear entire screen
    .replace(/\x1b\[K/g, '')  // clear line
    .replace(/\x1b\[2K/g, '')  // clear entire line
    .replace(/\x1b\[s/g, '')  // save cursor
    .replace(/\x1b\[u/g, '')  // restore cursor
    .replace(/\x1b\[\?25h/g, '')  // show cursor
    .replace(/\x1b\[\?25l/g, '')  // hide cursor
    // Cores - converter para spans
    .replace(/\x1b\[0m/g, '</span>')
    .replace(/\x1b\[1m/g, '<span class="font-bold">')
    .replace(/\x1b\[30m/g, '<span class="text-gray-900">')
    .replace(/\x1b\[31m/g, '<span class="text-red-500">')
    .replace(/\x1b\[32m/g, '<span class="text-green-500">')
    .replace(/\x1b\[33m/g, '<span class="text-yellow-500">')
    .replace(/\x1b\[34m/g, '<span class="text-blue-500">')
    .replace(/\x1b\[35m/g, '<span class="text-purple-500">')
    .replace(/\x1b\[36m/g, '<span class="text-cyan-500">')
    .replace(/\x1b\[37m/g, '<span class="text-gray-100">')
    .replace(/\x1b\[90m/g, '<span class="text-gray-500">')
    .replace(/\x1b\[91m/g, '<span class="text-red-400">')
    .replace(/\x1b\[92m/g, '<span class="text-green-400">')
    .replace(/\x1b\[93m/g, '<span class="text-yellow-400">')
    .replace(/\x1b\[94m/g, '<span class="text-blue-400">')
    .replace(/\x1b\[95m/g, '<span class="text-purple-400">')
    .replace(/\x1b\[96m/g, '<span class="text-cyan-400">')
    .replace(/\x1b\[97m/g, '<span class="text-white">')
    // Limpar outras sequencias ANSI
    .replace(/\x1b\[[0-9;]*[a-zA-Z]/g, '')
    .replace(/\x1b\][^\x07]*\x07/g, '')
    .replace(/\x1b[()][AB012]/g, '');
  
  return result;
}

export default function Terminal() {
  const [sessions, setSessions] = useState([]);
  const [activeSessionId, setActiveSessionId] = useState(null);
  const [devices, setDevices] = useState([]);
  const [showDeviceList, setShowDeviceList] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  
  // Configuracoes
  const [settings, setSettings] = useState({
    fontSize: 14,
    fontFamily: 'Monaco, Menlo, "Ubuntu Mono", monospace',
    bgColor: '#000000',
    textColor: '#ffffff',
    cursorColor: '#00ff00'
  });

  const terminalRef = useRef(null);
  const containerRef = useRef(null);

  // Carregar configuracoes salvas
  useEffect(() => {
    const saved = localStorage.getItem('terminalSettings');
    if (saved) {
      setSettings(JSON.parse(saved));
    }
  }, []);

  // Salvar configuracoes
  useEffect(() => {
    localStorage.setItem('terminalSettings', JSON.stringify(settings));
  }, [settings]);

  // Carregar dispositivos
  useEffect(() => {
    fetch('/devices/api/list/')
      .then(res => res.json())
      .then(data => {
        const list = data.devices || data || [];
        setDevices(list.map(d => ({
          id: d.id,
          name: d.hostname || d.name,
          ip: d.ip_address || d.ip,
          vendor: d.vendor || 'linux',
          username: d.username || 'admin',
          port: d.port || 22
        })));
      })
      .catch(() => setDevices([]));
  }, []);

  // Scroll automatico
  useEffect(() => {
    if (terminalRef.current) {
      terminalRef.current.scrollTop = terminalRef.current.scrollHeight;
    }
  }, [sessions]);

  // Foco no container
  useEffect(() => {
    if (containerRef.current) {
      containerRef.current.focus();
    }
  }, [activeSessionId]);

  const activeSession = sessions.find(s => s.id === activeSessionId);

  // Conectar ao dispositivo
  const connectToDevice = (device) => {
    const sessionId = 'session-' + Date.now();
    
    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
    const wsUrl = protocol + '//' + window.location.host + '/ws/ssh/';
    
    const ws = new WebSocket(wsUrl);
    
    const newSession = {
      id: sessionId,
      device: device,
      output: [],
      rawBuffer: '',
      ws: ws,
      status: 'connecting'
    };
    
    ws.onopen = () => {
      ws.send(JSON.stringify({
        type: 'connect',
        device_id: device.id
      }));
    };
    
    ws.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        const message = data.data || data.message || '';
        
        setSessions(prev => prev.map(s => {
          if (s.id === sessionId) {
            const newOutput = [...s.output, message];
            return { 
              ...s, 
              output: newOutput,
              rawBuffer: s.rawBuffer + message,
              status: data.type === 'connected' ? 'connected' : s.status
            };
          }
          return s;
        }));
      } catch (e) {
        setSessions(prev => prev.map(s => {
          if (s.id === sessionId) {
            return { ...s, output: [...s.output, event.data] };
          }
          return s;
        }));
      }
    };
    
    ws.onerror = () => {
      setSessions(prev => prev.map(s => {
        if (s.id === sessionId) {
          return { 
            ...s, 
            status: 'error',
            output: [...s.output, '\r\n[ERRO] Falha na conexao WebSocket\r\n']
          };
        }
        return s;
      }));
    };
    
    ws.onclose = () => {
      setSessions(prev => prev.map(s => {
        if (s.id === sessionId) {
          return { 
            ...s, 
            status: 'disconnected',
            output: [...s.output, '\r\n[DESCONECTADO]\r\n']
          };
        }
        return s;
      }));
    };
    
    setSessions(prev => [...prev, newSession]);
    setActiveSessionId(sessionId);
    setShowDeviceList(false);
  };

  // Enviar caractere
  const sendChar = useCallback((char) => {
    if (activeSession && activeSession.ws && activeSession.ws.readyState === WebSocket.OPEN) {
      activeSession.ws.send(JSON.stringify({ data: char }));
    }
  }, [activeSession]);

  // Handler de teclas - TERMINAL REAL
  const handleKeyDown = useCallback((e) => {
    e.preventDefault();
    e.stopPropagation();
    
    // TAB
    if (e.key === 'Tab') {
      sendChar('\t');
      return false;
    }
    
    // Enter
    if (e.key === 'Enter') {
      sendChar('\r');
      return false;
    }
    
    // Backspace
    if (e.key === 'Backspace') {
      sendChar('\x7f');
      return false;
    }
    
    // Delete
    if (e.key === 'Delete') {
      sendChar('\x1b[3~');
      return false;
    }
    
    // Ctrl+C
    if (e.key === 'c' && e.ctrlKey) {
      sendChar('\x03');
      return false;
    }
    
    // Ctrl+D
    if (e.key === 'd' && e.ctrlKey) {
      sendChar('\x04');
      return false;
    }
    
    // Ctrl+Z
    if (e.key === 'z' && e.ctrlKey) {
      sendChar('\x1a');
      return false;
    }
    
    // Ctrl+A (inicio da linha)
    if (e.key === 'a' && e.ctrlKey) {
      sendChar('\x01');
      return false;
    }
    
    // Ctrl+E (fim da linha)
    if (e.key === 'e' && e.ctrlKey) {
      sendChar('\x05');
      return false;
    }
    
    // Ctrl+U (limpar linha)
    if (e.key === 'u' && e.ctrlKey) {
      sendChar('\x15');
      return false;
    }
    
    // Ctrl+K (cortar ate o fim)
    if (e.key === 'k' && e.ctrlKey) {
      sendChar('\x0b');
      return false;
    }
    
    // Ctrl+W (apagar palavra)
    if (e.key === 'w' && e.ctrlKey) {
      sendChar('\x17');
      return false;
    }
    
    // Setas
    if (e.key === 'ArrowUp') {
      sendChar('\x1b[A');
      return false;
    }
    if (e.key === 'ArrowDown') {
      sendChar('\x1b[B');
      return false;
    }
    if (e.key === 'ArrowRight') {
      sendChar('\x1b[C');
      return false;
    }
    if (e.key === 'ArrowLeft') {
      sendChar('\x1b[D');
      return false;
    }
    
    // Home/End
    if (e.key === 'Home') {
      sendChar('\x1b[H');
      return false;
    }
    if (e.key === 'End') {
      sendChar('\x1b[F');
      return false;
    }
    
    // Page Up/Down
    if (e.key === 'PageUp') {
      sendChar('\x1b[5~');
      return false;
    }
    if (e.key === 'PageDown') {
      sendChar('\x1b[6~');
      return false;
    }
    
    // Escape
    if (e.key === 'Escape') {
      sendChar('\x1b');
      return false;
    }
    
    // Caractere normal
    if (e.key.length === 1) {
      sendChar(e.key);
      return false;
    }
    
    return false;
  }, [sendChar, activeSession]);

  // Fechar sessao
  const closeSession = (sessionId) => {
    const session = sessions.find(s => s.id === sessionId);
    if (session && session.ws) {
      session.ws.close();
    }
    setSessions(prev => prev.filter(s => s.id !== sessionId));
    if (activeSessionId === sessionId) {
      const remaining = sessions.filter(s => s.id !== sessionId);
      setActiveSessionId(remaining.length > 0 ? remaining[0].id : null);
    }
  };

  // Renderizar output processado
  const renderOutput = (output) => {
    const fullText = output.join('');
    const processed = processAnsi(fullText);
    return processed;
  };

  return (
    <div 
      className={'h-full flex flex-col' + (isFullscreen ? ' fixed inset-0 z-50' : '')}
      style={{ backgroundColor: settings.bgColor }}
    >
      {/* Header */}
      <div className="flex items-center justify-between bg-gray-800 border-b border-gray-700 px-4 py-2">
        <div className="flex items-center gap-2">
          <h1 className="text-lg font-bold text-white">Terminal SSH</h1>
          <button
            onClick={() => setShowDeviceList(!showDeviceList)}
            className="flex items-center gap-1 px-2 py-1 bg-blue-600 text-white rounded text-sm hover:bg-blue-700"
          >
            <Plus className="w-4 h-4" /> Nova
          </button>
        </div>
        <div className="flex items-center gap-2">
          <button
            onClick={() => setShowSettings(!showSettings)}
            className="p-1.5 rounded hover:bg-gray-700 text-gray-300"
            title="Configuracoes"
          >
            <Settings className="w-4 h-4" />
          </button>
          <button
            onClick={() => setIsFullscreen(!isFullscreen)}
            className="p-1.5 rounded hover:bg-gray-700 text-gray-300"
          >
            {isFullscreen ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
          </button>
        </div>
      </div>

      {/* Device List */}
      {showDeviceList && (
        <div className="absolute top-12 left-4 z-50 bg-gray-800 border border-gray-600 rounded-lg shadow-xl p-3 w-72">
          <h3 className="font-semibold mb-2 text-white text-sm">Dispositivos</h3>
          <div className="space-y-1 max-h-48 overflow-auto">
            {devices.length === 0 ? (
              <p className="text-gray-400 text-xs">Nenhum dispositivo</p>
            ) : (
              devices.map(device => (
                <button
                  key={device.id}
                  onClick={() => connectToDevice(device)}
                  className="w-full flex items-center gap-2 p-1.5 rounded hover:bg-gray-700 text-left text-sm"
                >
                  <div className={'w-2 h-2 rounded-full ' + 
                    (device.vendor === 'huawei' ? 'bg-red-500' :
                     device.vendor === 'mikrotik' ? 'bg-green-500' :
                     device.vendor === 'cisco' ? 'bg-blue-500' : 'bg-yellow-500')}
                  />
                  <div>
                    <div className="text-white text-xs">{device.name}</div>
                    <div className="text-gray-400 text-xs">{device.ip}</div>
                  </div>
                </button>
              ))
            )}
          </div>
        </div>
      )}

      {/* Settings Panel */}
      {showSettings && (
        <div className="absolute top-12 right-4 z-50 bg-gray-800 border border-gray-600 rounded-lg shadow-xl p-4 w-64">
          <h3 className="font-semibold mb-3 text-white">Configuracoes</h3>
          
          <div className="space-y-3">
            <div>
              <label className="text-gray-300 text-xs">Tamanho da Fonte</label>
              <input
                type="range"
                min="10"
                max="24"
                value={settings.fontSize}
                onChange={(e) => setSettings({...settings, fontSize: parseInt(e.target.value)})}
                className="w-full"
              />
              <span className="text-gray-400 text-xs">{settings.fontSize}px</span>
            </div>
            
            <div>
              <label className="text-gray-300 text-xs">Fundo</label>
              <input
                type="color"
                value={settings.bgColor}
                onChange={(e) => setSettings({...settings, bgColor: e.target.value})}
                className="w-full h-8 rounded cursor-pointer"
              />
            </div>
            
            <div>
              <label className="text-gray-300 text-xs">Texto</label>
              <input
                type="color"
                value={settings.textColor}
                onChange={(e) => setSettings({...settings, textColor: e.target.value})}
                className="w-full h-8 rounded cursor-pointer"
              />
            </div>
            
            <div>
              <label className="text-gray-300 text-xs">Cursor</label>
              <input
                type="color"
                value={settings.cursorColor}
                onChange={(e) => setSettings({...settings, cursorColor: e.target.value})}
                className="w-full h-8 rounded cursor-pointer"
              />
            </div>
          </div>
        </div>
      )}

      {/* Session Tabs */}
      {sessions.length > 0 && (
        <div className="flex bg-gray-900 border-b border-gray-700 overflow-x-auto">
          {sessions.map(session => (
            <div
              key={session.id}
              onClick={() => setActiveSessionId(session.id)}
              className={'flex items-center gap-2 px-3 py-1.5 border-r border-gray-700 cursor-pointer text-sm ' +
                (activeSessionId === session.id ? 'bg-gray-800' : 'hover:bg-gray-800')}
            >
              <div className={'w-2 h-2 rounded-full ' +
                (session.status === 'connected' ? 'bg-green-500' :
                 session.status === 'connecting' ? 'bg-yellow-500 animate-pulse' :
                 session.status === 'error' ? 'bg-red-500' : 'bg-gray-500')}
              />
              <span className="text-gray-200">{session.device.name}</span>
              <button
                onClick={(e) => { e.stopPropagation(); closeSession(session.id); }}
                className="p-0.5 rounded hover:bg-red-500/30 text-gray-400"
              >
                <X className="w-3 h-3" />
              </button>
            </div>
          ))}
        </div>
      )}

      {/* Terminal Area */}
      <div
        ref={containerRef}
        className="flex-1 overflow-auto p-2 outline-none"
        style={{ 
          backgroundColor: settings.bgColor,
          fontFamily: settings.fontFamily,
          fontSize: settings.fontSize + 'px'
        }}
        tabIndex={0}
        onKeyDown={handleKeyDown}
      >
        {sessions.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-gray-500">
            <p className="text-lg">Nenhuma sessao ativa</p>
            <p className="text-sm">Clique em "Nova" para conectar</p>
          </div>
        ) : activeSession ? (
          <div className="relative">
            <pre 
              ref={terminalRef}
              className="whitespace-pre-wrap break-all leading-relaxed"
              style={{ color: settings.textColor }}
              dangerouslySetInnerHTML={{ __html: renderOutput(activeSession.output) }}
            />
            {/* Cursor piscando */}
            <span 
              className="inline-block w-2 animate-pulse"
              style={{ 
                backgroundColor: settings.cursorColor,
                height: settings.fontSize + 'px',
                verticalAlign: 'bottom'
              }}
            />
          </div>
        ) : null}
      </div>

      {/* Status Bar */}
      {activeSession && (
        <div 
          className="flex items-center justify-between px-4 py-1 text-xs border-t"
          style={{ backgroundColor: '#1a1a1a', borderColor: '#333', color: '#888' }}
        >
          <div className="flex items-center gap-4">
            <span className="flex items-center gap-1.5">
              <div className={'w-2 h-2 rounded-full ' +
                (activeSession.status === 'connected' ? 'bg-green-500' :
                 activeSession.status === 'connecting' ? 'bg-yellow-500' : 'bg-red-500')}
              />
              {activeSession.status === 'connected' ? 'Conectado' :
               activeSession.status === 'connecting' ? 'Conectando...' : 'Desconectado'}
            </span>
            <span>{activeSession.device.name} ({activeSession.device.ip})</span>
          </div>
          <span>TAB: completar | Ctrl+C: cancelar | Setas: navegar</span>
        </div>
      )}
    </div>
  );
}
